@module paramAutomation  src=paramAutomation.lua  loc=433  sha=d15eb89  mode=chunk  self=pa
@deps cm, ds, facade, ccm

# Invariants & contracts
  @invariant  automation bus is 126 — 127 is wiring's parking bus, wiring allocates 0..125  @ 4
  @invariant  authored (chan,lane) codes are track-unique across takes; bus codes project-unique  @ 5

# Shapes
  @shape  binding = { busCode=int, trackGuid=str, fxGuid=str, param=int, scale=num, offset=num, label=str }  @ 6
  @shape  trackSpec = { filter={ {src=code,dst=code},... }, listen={ {code,fxGuid,param,scale,offset},... }, sends={dstGuid,...} }  @ 7
  @shape  paramFrecency (ds global) = { [fxIdent] = { n=int, params={ [paramIndex]={s=num,n0=int} } } }  @ 8

# Imports
  @require util = 'util'  @ 10
      @contract  apply() is a full-project idempotent reconcile; mirror-matching tracks are untouched  @ 9

